import { CommonModule } from '@angular/common';
import { Component, computed, Inject, inject } from '@angular/core';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { MatFormFieldModule, MatLabel } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { MatSnackBarModule } from '@angular/material/snack-bar';
import { LoaderComponent } from '../../shared/loader/loader.component';
import { LoaderService } from '../../shared/loader/loader.service';
import { allowLimitedInput, allowOnlyLetters, } from '../../pages/master/master.utils';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { SnackbarService } from '../../shared/snack-bar/snack-bar.service';
import { TariffService } from '../../pages/master/tariff-services/tariff-services.service';
import { MaCountry } from '../../pages/master/country/country.model';
import { MatSelect } from '@angular/material/select';
import { MatOption } from '@angular/material/core';
import { atLeastOneFieldRequiredValidator, } from '../../pages/master/tariff-services/tariff-service.model';

@Component({
  selector: 'app-create-tariff-service',
  standalone: true,
  imports: [MatFormFieldModule,
    MatLabel, MatIconModule, MatInputModule, ReactiveFormsModule, CommonModule, MatSnackBarModule, LoaderComponent, MatOption, MatSelect],
  templateUrl: './create-tariff-service.component.html',
  styleUrl: './create-tariff-service.component.css'
})
export class CreateTariffServiceComponent {

  private loader = inject(LoaderService);
  isLoading = computed(() => this.loader.loading());
  disallowNumericData = allowOnlyLetters;
  allowLimitedInput = allowLimitedInput;
  serviceForm: FormGroup;
  isEditMode = false;
  countryData: MaCountry[] = [];

  constructor(
    private fb: FormBuilder,
    private dialogRef: MatDialogRef<CreateTariffServiceComponent>,
    @Inject(MAT_DIALOG_DATA) public existingdata: any,
    private tariffService: TariffService,
    // private countryService: CountryService,
    private snackBar: SnackbarService
  ) {
    const data = existingdata?.rowData;
    this.isEditMode = !!data;
    this.serviceForm = this.fb.group({
      service_id: [data?.service_id ?? null],
      service_name: [data?.service_name || '', Validators.required],
      fields: this.fb.array(
        (data?.fields ?? []).map((field: any) =>
          this.fb.group({
            name: [field.name || ''],
            data_type: [field.data_type || ''],
            nullable: [field.nullable || 'Optional'],
          })
        ),
        [atLeastOneFieldRequiredValidator]
      )
    });

  }

  // onPaste(event: ClipboardEvent): void {
  //   const value = handlePasteText(event);
  //   this.serviceForm.get('type')?.setValue(value);
  // }

  ngOnInit() {
    // this.getMaCountryDataFromDb();
  }
  get fields() {
    return this.serviceForm.get('fields') as any;
  }

  // method to add the additional fields
  addField() {
    this.fields.push(
      this.fb.group({
        name: ['', Validators.required],
        data_type: ['', Validators.required],
        nullable: ['',],

      })
    )
  }

  removeField(index: number) {
    if (index >= 0) {
      this.fields.removeAt(index);
    }
  }

  // onSubmit method will trigger when the Add or Edit  button clicks
  onSubmit() {
    if (atLeastOneFieldRequiredValidator(this.fields)) {
      // this.fields.markAsTouched();
      this.snackBar.showError('At least one field is required.');
      return;
    }

    if (this.fields.invalid) {
      this.fields.markAsTouched();
      this.snackBar.showError('Please fill the required fields');
      return;
    }
    if (this.serviceForm.valid) {
      this.loader.show();
      this.tariffService.ServiceDataToDB(this.serviceForm.value).subscribe({
        next: (res) => {
          this.loader.hide();
          this.snackBar.showSuccess(res.message);
          this.dialogRef.close("refresh");
        },
        error: (error) => {
          this.loader.hide();
          const errorMsg = error.error?.error || 'Something went wrong. Please try again.';
          this.snackBar.showError(errorMsg);
        }
      })
    }
  }

  // method to get the countrylist
  // getMaCountryDataFromDb() {
  //   const body = {
  //     fields: [
  //       "country"
  //     ]

  //   }
  //   this.loader.show();
  //   this.countryService.MaCountryDataFromDb(body).subscribe({
  //     next: (response: any) => {
  //       this.countryData = response;
  //       this.loader.hide();
  //     },
  //     error: (err) => {
  //       console.error('Error fetching countries:', err);
  //       this.loader.hide();
  //     }
  //   });
  // }

  closeDialog() {
    this.dialogRef.close("");
  }

}
